const { AppError, divide, checkToken, validateName, toCents, parseIntStrict, clamp, get, padLeft, parseIso } = require('./src/index.js');

// Verify AppError shape
const e = new AppError('FOO', 'bar baz');
console.assert(e instanceof Error, 'not Error');
console.assert(e instanceof AppError, 'not AppError');
console.assert(e.name === 'AppError', 'wrong name');
console.assert(e.code === 'FOO', 'wrong code');
console.assert(e.message === 'bar baz', 'wrong message');

// Verify each throw site produces AppError with correct code/message
function check(fn, code, msg) {
  try { fn(); } catch(err) {
    console.assert(err instanceof AppError, code + ' not AppError');
    console.assert(err.code === code, code + ' wrong code: ' + err.code);
    console.assert(err.message === msg, code + ' wrong msg: ' + err.message);
    console.assert(!err.message.includes(':'), code + ' message still has colon');
  }
}

check(() => divide(1, 0), 'DIV_ZERO', 'division by zero');
check(() => checkToken('bad'), 'BAD_TOKEN', 'token malformed');
check(() => validateName('  '), 'EMPTY_NAME', 'name required');
check(() => toCents(-1), 'NEG_AMOUNT', 'amount below zero');
check(() => parseIntStrict('x'), 'BAD_INT', 'not an integer');
check(() => clamp(0, 5, 1), 'BAD_RANGE', 'min above max');
check(() => get('missing'), 'MISSING_KEY', 'no such key');
check(() => padLeft('x', 0), 'BAD_WIDTH', 'width must be positive');
check(() => parseIso('not-a-date'), 'BAD_DATE', 'not an ISO date');

// Success paths unchanged
console.assert(divide(10, 2) === 5, 'divide broken');
console.assert(checkToken('tk_abc123') === true, 'checkToken broken');
console.assert(validateName(' hello ') === 'hello', 'validateName broken');
console.assert(toCents(1.5) === 150, 'toCents broken');
console.assert(parseIntStrict('42') === 42, 'parseIntStrict broken');
console.assert(clamp(3, 1, 5) === 3, 'clamp broken');
const { set } = require('./src/store.js'); set('k', 'v');
console.assert(get('k') === 'v', 'store broken');
console.assert(padLeft('x', 5) === '    x', 'padLeft broken');
console.assert(parseIso('2024-01-15').toISOString().startsWith('2024-01-15'), 'parseIso broken');

console.log('All checks passed');
